-- ============================================
-- CAS BOULANGERIE DE LUXE — Patisserie artisanale Lausanne
-- Version SQLite — 6 tables, ~130 lignes
-- ============================================
CREATE TABLE categorie (id_categorie INTEGER PRIMARY KEY AUTOINCREMENT, nom_categorie TEXT NOT NULL, description TEXT);
CREATE TABLE produit (id_produit INTEGER PRIMARY KEY AUTOINCREMENT, id_categorie INTEGER NOT NULL REFERENCES categorie(id_categorie), nom_produit TEXT NOT NULL, prix_unitaire REAL NOT NULL, disponible INTEGER NOT NULL DEFAULT 1, temps_preparation_min INTEGER, allergenes TEXT);
CREATE TABLE ingredient (id_ingredient INTEGER PRIMARY KEY AUTOINCREMENT, nom_ingredient TEXT NOT NULL, unite TEXT NOT NULL, prix_kg REAL, bio INTEGER NOT NULL DEFAULT 0, allergene_principal TEXT);
CREATE TABLE produit_ingredient (id_produit INTEGER NOT NULL REFERENCES produit(id_produit), id_ingredient INTEGER NOT NULL REFERENCES ingredient(id_ingredient), quantite REAL NOT NULL, PRIMARY KEY (id_produit, id_ingredient));
CREATE TABLE client (id_client INTEGER PRIMARY KEY AUTOINCREMENT, nom TEXT NOT NULL, prenom TEXT NOT NULL, email TEXT UNIQUE, telephone TEXT NOT NULL, ville TEXT, client_regulier INTEGER NOT NULL DEFAULT 0);
CREATE TABLE commande (id_commande INTEGER PRIMARY KEY AUTOINCREMENT, id_client INTEGER NOT NULL REFERENCES client(id_client), id_produit INTEGER NOT NULL REFERENCES produit(id_produit), quantite INTEGER NOT NULL DEFAULT 1, date_commande TEXT NOT NULL, date_livraison TEXT NOT NULL, personnalisation TEXT, montant_total REAL NOT NULL, statut TEXT NOT NULL DEFAULT 'En attente');

